import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  server: {
    proxy: {
      "/vietqr-api": {
        target: "https://api.vietqr.io",
        changeOrigin: true,
        rewrite: (p) => p.replace(/^\/vietqr-api/, ""),
      },
    },
  },
});

export type VietQrBusiness = {
  id: string;
  name: string;
  internationalName: string;
  shortName: string;
  address: string;
};

export type VietQrResponse = {
  code: string;
  desc: string;
  data: VietQrBusiness | null;
};

export type ResearchOutput = {
  legalForm: string;
  inferredSector: string;
  region: string;
  profileBullets: string[];
  dataSources: string[];
};

export type ReportOutput = {
  executiveSummary: string;
  recommendations: string[];
  keyEntities: { label: string; value: string }[];
};

export type VerificationOutput = {
  trustScore: number;
  riskFlags: { level: "low" | "medium" | "high"; message: string }[];
  complianceNotes: string[];
};

export type PipelineState = {
  mst: string;
  raw: VietQrResponse | null;
  research: ResearchOutput | null;
  report: ReportOutput | null;
  verification: VerificationOutput | null;
  step: "idle" | "fetching" | "research" | "report" | "verification" | "done" | "error";
  error: string | null;
};

export type CrmPurpose = "kyc" | "credit" | "audit" | "partnership";

export type CrmSegment = "Enterprise" | "SME" | "Startup" | "Risky" | "Inactive";

export type CrmInsight = {
  segment: CrmSegment;
  rationale: string[];
  purposeAdjustments: string[];
  suggestedNextSteps: string[];
};

export type SampleCompany = {
  id: string;
  label: string;
  mst: string;
  note: string;
};

import type { SampleCompany } from "../types";

/** Mẫu MST công khai thường dùng tra cứu; có thể thay đổi theo dữ liệu VietQR. */
export const SAMPLE_COMPANIES: SampleCompany[] = [
  {
    id: "viettel",
    label: "Tập đoàn Công nghiệp Viễn thông Quân đội (Viettel)",
    mst: "0100109106",
    note: "Doanh nghiệp nhà nước / tập đoàn",
  },
  {
    id: "vietcombank",
    label: "Ngân hàng TMCP Ngoại thương Việt Nam (Vietcombank)",
    mst: "0102126770",
    note: "Ngân hàng niêm yết",
  },
  {
    id: "vingroup",
    label: "Tập đoàn Vingroup",
    mst: "0101241596",
    note: "Holding đa ngành",
  },
  {
    id: "vinamilk",
    label: "Công ty CP Sữa Việt Nam (Vinamilk)",
    mst: "0300588569",
    note: "DN CP lớn",
  },
];

import type { VietQrResponse } from "../types";

const PATH = "/vietqr-api/v2/business";

function normalizeMst(input: string): string {
  return input.replace(/\D/g, "").trim();
}

export async function fetchBusinessByTaxCode(mstRaw: string): Promise<VietQrResponse> {
  const taxCode = normalizeMst(mstRaw);
  if (!taxCode) {
    return { code: "98", desc: "MST rỗng", data: null };
  }

  const url = `${PATH}/${encodeURIComponent(taxCode)}`;
  const res = await fetch(url, { headers: { Accept: "application/json" } });
  const body = (await res.json()) as VietQrResponse;

  if (!res.ok) {
    return {
      code: String(res.status),
      desc: body?.desc ?? res.statusText,
      data: null,
    };
  }
  return body;
}

export { normalizeMst };

import type {
  ReportOutput,
  ResearchOutput,
  VerificationOutput,
  VietQrBusiness,
  VietQrResponse,
} from "../types";

const DELAY_MS = 380;

function sleep(ms: number) {
  return new Promise((r) => setTimeout(r, ms));
}

function inferLegalForm(name: string): string {
  const u = name.toUpperCase();
  if (u.includes("CÔNG TY CỔ PHẦN") || u.includes("CTCP")) return "Công ty cổ phần";
  if (u.includes("CÔNG TY TNHH MTV")) return "TNHH một thành viên";
  if (u.includes("CÔNG TY TNHH")) return "TNHH";
  if (u.includes("TỔNG CÔNG TY")) return "Tổng công ty";
  if (u.includes("NGÂN HÀNG")) return "Tổ chức tín dụng";
  if (u.includes("HỢP DANH")) return "Hợp danh";
  if (u.includes("DOANH NGHIỆP TƯ NHÂN") || u.includes("DNTN")) return "Doanh nghiệp tư nhân";
  return "Chưa phân loại rõ (cần tra Cổng thông tin quốc gia về đăng ký doanh nghiệp)";
}

function inferSector(name: string, intl: string): string {
  const blob = `${name} ${intl}`.toLowerCase();
  const rules: [RegExp, string][] = [
    [/ngân hàng|bank|tín dụng/, "Tài chính – ngân hàng"],
    [/viễn thông|telecom|viettel|mobifone|vinaphone/, "Viễn thông – CNTT"],
    [/sữa|dairy|milk|thực phẩm|food/, "Thực phẩm – FMCG"],
    [/bất động sản|real estate|vingroup|vinhomes/, "Bất động sản – hạ tầng"],
    [/ô tô|xe|automotive/, "Cơ khí – ô tô"],
    [/dược|pharma|y tế/, "Dược – y tế"],
  ];
  for (const [re, label] of rules) {
    if (re.test(blob)) return label;
  }
  return "Chung (cần bổ sung ngành từ nguồn đăng ký kinh doanh)";
}

function inferRegion(address: string): string {
  const u = address.toUpperCase();
  const cities = [
    "HÀ NỘI",
    "TP. HỒ CHÍ MINH",
    "HỒ CHÍ MINH",
    "ĐÀ NẴNG",
    "HẢI PHÒNG",
    "CẦN THƠ",
    "THỦ ĐỨC",
  ];
  for (const c of cities) {
    if (u.includes(c)) return c;
  }
  if (address.length > 10) return "Khu vực trong nước (chi tiết từ địa chỉ VietQR)";
  return "Chưa xác định";
}

export async function runResearchAgent(data: VietQrBusiness): Promise<ResearchOutput> {
  await sleep(DELAY_MS);
  const legalForm = inferLegalForm(data.name);
  const sector = inferSector(data.name, data.internationalName);
  const region = inferRegion(data.address);
  const profileBullets = [
    `Tên đăng ký: ${data.name}`,
    `Tên quốc tế: ${data.internationalName || "—"}`,
    `Tên ngắn: ${data.shortName || "—"}`,
    `Địa chỉ trụ sở (VietQR): ${data.address}`,
    `Hình thức pháp lý (suy luận từ tên): ${legalForm}`,
    `Nhóm ngành (heuristic): ${sector}`,
    `Địa bàn ưu tiên: ${region}`,
  ];
  return {
    legalForm,
    inferredSector: sector,
    region,
    profileBullets,
    dataSources: [
      "VietQR API — GET /v2/business/{taxCode} (tên, địa chỉ, tên quốc tế)",
      "Heuristic nội bộ — phân tích pattern tên DN (không thay thế tra cứu pháp lý đầy đủ)",
    ],
  };
}

export async function runReportAgent(
  data: VietQrBusiness,
  research: ResearchOutput,
): Promise<ReportOutput> {
  await sleep(DELAY_MS);
  const executiveSummary = [
    `Doanh nghiệp ${data.shortName || data.name} (MST ${data.id}) được định vị trong nhóm ngành “${research.inferredSector}”, `,
    `hình thức pháp lý gợi ý: ${research.legalForm}. `,
    `Trụ sở ghi nhận tại ${research.region}. `,
    `Khuyến nghị đối chiếu thêm dữ liệu đăng ký kinh doanh và tình trạng hoạt động tại cơ quan thuế trước khi ra quyết định tín dụng hoặc hợp tác chiến lược.`,
  ].join("");

  const recommendations = [
    "Xác thực MST với hóa đơn điện tử / CQT khi dùng cho KYC thanh toán.",
    "Đối chiếu người đại diện pháp luật và vốn điều lệ từ nguồn đăng ký doanh nghiệp.",
    "Với mục đích tín dụng: yêu cầu BCTC hoặc xếp hạng nội bộ bổ sung.",
  ];

  const keyEntities = [
    { label: "MST", value: data.id },
    { label: "Tên hiển thị", value: data.name },
    { label: "Ngành (AI Research)", value: research.inferredSector },
    { label: "Địa bàn", value: research.region },
  ];

  return { executiveSummary, recommendations, keyEntities };
}

function nameConsistencyScore(vn: string, intl: string): { ok: boolean; note: string } {
  if (!intl || intl.length < 3) {
    return { ok: false, note: "Thiếu hoặc quá ngắn tên quốc tế — khó đối chiếu chéo." };
  }
  const a = vn
    .toUpperCase()
    .replace(/[^A-ZÀÁẢÃẠĂẰẮẲẴẶÂẦẤẨẪẬĐÈÉẺẼẸÊỀẾỂỄỆÌÍỈĨỊÒÓỎÕỌÔỒỐỔỖỘƠỜỚỞỠỢÙÚỦŨỤƯỪỨỬỰỲÝỶỸỴa-zàáảãạăằắẳẵặâầấẩẫậđèéẻẽẹêềếểễệìíỉĩịòóỏõọôồốổỗộơờớởỡợùúủũụưừứửựỳýỷỹỵ]/g, "");
  const short = intl.slice(0, 4).toUpperCase();
  if (a.includes(short) || intl.length > 12) {
    return { ok: true, note: "Tên quốc tế và tên trong nước có độ tương thích chấp nhận được." };
  }
  return { ok: false, note: "Độ khớp tên VI/EN thấp — nên kiểm tra thủ công." };
}

export async function runVerificationAgent(
  data: VietQrBusiness,
  research: ResearchOutput,
): Promise<VerificationOutput> {
  await sleep(DELAY_MS);
  const riskFlags: VerificationOutput["riskFlags"] = [];
  const nm = nameConsistencyScore(data.name, data.internationalName);
  if (!nm.ok) {
    riskFlags.push({ level: "medium", message: nm.note });
  }
  if (data.address.length < 25) {
    riskFlags.push({
      level: "low",
      message: "Địa chỉ ngắn — có thể là chi nhánh hoặc dữ liệu rút gọn.",
    });
  }
  const highRiskKw = /mua bán nợ|thanh lý|xuất khẩu lao động|tín dụng đen/i;
  if (highRiskKw.test(data.name)) {
    riskFlags.push({
      level: "high",
      message: "Từ khóa rủi ro trong tên — cần rà soát thêm (quy tắc nội bộ).",
    });
  }

  let trustScore = 72;
  if (nm.ok) trustScore += 10;
  if (data.address.length > 40) trustScore += 6;
  if (research.legalForm.includes("cổ phần") || research.legalForm.includes("Tổng công ty")) {
    trustScore += 4;
  }
  trustScore -= riskFlags.filter((f) => f.level === "high").length * 25;
  trustScore -= riskFlags.filter((f) => f.level === "medium").length * 12;
  trustScore -= riskFlags.filter((f) => f.level === "low").length * 4;
  trustScore = Math.max(18, Math.min(96, Math.round(trustScore)));

  const complianceNotes = [
    "Điểm tin cậy mang tính minh họa pipeline; không thay thế scoring tín dụng.",
    "Luồng này chỉ dùng dữ liệu VietQR + luật heuristic — bổ sung PEP/sanctions theo chính sách nội bộ.",
  ];

  return { trustScore, riskFlags, complianceNotes };
}

export async function runFullPipeline(response: VietQrResponse): Promise<{
  research: ResearchOutput;
  report: ReportOutput;
  verification: VerificationOutput;
}> {
  if (response.code !== "00" || !response.data) {
    throw new Error(response.desc || "Không có dữ liệu doanh nghiệp từ VietQR");
  }
  const data = response.data;
  const research = await runResearchAgent(data);
  const report = await runReportAgent(data, research);
  const verification = await runVerificationAgent(data, research);
  return { research, report, verification };
}

import type { CrmInsight, CrmPurpose, CrmSegment, VerificationOutput, VietQrBusiness } from "../types";

function baseSegment(data: VietQrBusiness, verification: VerificationOutput | null): CrmSegment {
  if (verification && verification.trustScore < 35) return "Risky";
  const n = `${data.name} ${data.shortName}`.toUpperCase();
  const enterpriseHints =
    /TẬP ĐOÀN|TỔNG CÔNG TY|NGÂN HÀNG|VIETTEL|VINGROUP|VINAMILK|VIETCOMBANK|CTCP.*(SỮA|HÀNG KHÔNG)/;
  if (enterpriseHints.test(n)) return "Enterprise";
  if (/CÔNG TY TNHH MTV|CHI NHÁNH|TNHH/.test(n) && !/HỢP TÁC XÃ/.test(n)) return "SME";
  if (/KHỞI NGHIỆP|STARTUP|INNOVATION|LAB/.test(n)) return "Startup";
  if (verification && verification.riskFlags.some((f) => f.level === "high")) return "Risky";
  return "SME";
}

function purposeNarrative(
  purpose: CrmPurpose,
  segment: CrmSegment,
): { rationale: string[]; adjustments: string[]; steps: string[] } {
  const map: Record<
    CrmPurpose,
    { rationale: string[]; adjustments: string[]; steps: string[] }
  > = {
    kyc: {
      rationale: [
        "KYC: ưu tiên khớp MST – tên – địa chỉ với giấy tờ và hóa đơn mẫu.",
        `Phân khúc ${segment} ảnh hưởng mức độ giấy tờ bổ sung (ĐKKD, UBO).`,
      ],
      adjustments:
        segment === "Enterprise"
          ? ["Yêu cầu xác minh pháp nhân qua kênh chính thức hoặc ngân hàng đối tác."]
          : segment === "Startup"
            ? ["Chấp nhận địa chỉ đăng ký khác địa chỉ giao dịch nếu có hợp đồng thuê."]
            : ["Chuẩn hóa địa chỉ theo VietQR và đối chiếu mã bưu chính."],
      steps: ["Thu thập MST + scan ĐKKD", "Đối chiếu VietQR", "Lưu artifact vào CRM"],
    },
    credit: {
      rationale: [
        "Tín dụng: MST chỉ là tầng dữ liệu mở — cần BCTC và lịch sử nợ.",
        `Nhóm ${segment} quyết định hạn mức khởi điểm đề xuất.`,
      ],
      adjustments:
        segment === "Risky"
          ? ["Hạn chế tự động duyệt; chuyển thẩm định thủ công."]
          : ["Cho phép scoring tự động sơ bộ nếu trust score đủ cao."],
      steps: ["Import VietQR", "Gắn cờ rủi ro", "Gửi sang hệ thống scoring"],
    },
    audit: {
      rationale: [
        "Kiểm toán: dùng MST để khóa đối tượng và đối chiếu chuỗi giao dịch.",
        "Segment giúp chọn mẫu kiểm tra và ngưỡng vật liệu chứng minh.",
      ],
      adjustments:
        segment === "Enterprise"
          ? ["Mở rộng phạm vi kiểm tra các công ty con liên quan."]
          : ["Tập trung kiểm tra dòng tiền và hóa đơn đầu vào."],
      steps: ["Snapshot hồ sơ VietQR", "Lưu hash thời điểm tra cứu", "Đính kèm working paper"],
    },
    partnership: {
      rationale: [
        "Thẩm định hợp tác: cần uy tín thương hiệu và tình trạng hoạt động.",
        "AI phân loại segment để định tần suất review định kỳ.",
      ],
      adjustments:
        segment === "Inactive"
          ? ["Tạm dừng đàm phán cho đến khi xác minh hoạt động."]
          : ["Tiến hành NDA và due diligence theo checklist ngành."],
      steps: ["Chạy pipeline 3 agent", "Lưu báo cáo điều hành", "Phân công owner đối tác"],
    },
  };
  return map[purpose];
}

export function buildCrmInsight(
  data: VietQrBusiness | null,
  verification: VerificationOutput | null,
  purpose: CrmPurpose,
  apiInactive: boolean,
): CrmInsight {
  if (apiInactive || !data) {
    const pn = purposeNarrative(purpose, "Inactive");
    return {
      segment: "Inactive",
      rationale: [
        "Không lấy được hồ sơ hợp lệ từ VietQR (MST sai, gián đoạn API hoặc DN không tồn tại trong nguồn).",
        ...pn.rationale,
      ],
      purposeAdjustments: [
        "Không sử dụng kết quả AI cho quyết định cho đến khi có MST hợp lệ.",
        ...pn.adjustments,
      ],
      suggestedNextSteps: ["Kiểm tra lại MST", "Tra cổng đăng ký doanh nghiệp", ...pn.steps],
    };
  }

  let segment = baseSegment(data, verification);
  const n = data.name.toUpperCase();
  if (/GIẢI THỂ|PHÁ SẢN|TẠM NGỪNG/.test(n)) {
    segment = "Inactive";
  }

  const pn = purposeNarrative(purpose, segment);
  return {
    segment,
    rationale: [
      `Phân khúc gợi ý: ${segment} (dựa trên tên DN, trust score và cờ rủi ro).`,
      ...pn.rationale,
    ],
    purposeAdjustments: pn.adjustments,
    suggestedNextSteps: pn.steps,
  };
}

:root {
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  line-height: 1.5;
  font-weight: 400;
  color: #0f172a;
  background: #f1f5f9;
  --stroke: #cbd5e1;
  --accent: #1d4ed8;
  --accent-soft: #dbeafe;
  --muted: #64748b;
  --card: #ffffff;
  --danger: #b91c1c;
  --warn: #b45309;
  --ok: #15803d;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
}

#root {
  min-height: 100vh;
}

.app-shell {
  max-width: 1120px;
  margin: 0 auto;
  padding: 1.25rem 1.25rem 2.5rem;
}

.app-header {
  margin-bottom: 1rem;
}

.app-header h1 {
  margin: 0 0 0.35rem;
  font-size: 1.35rem;
  font-weight: 650;
  letter-spacing: -0.02em;
}

.app-header p {
  margin: 0;
  color: var(--muted);
  font-size: 0.9rem;
}

.tabs {
  display: flex;
  gap: 0.25rem;
  border-bottom: 1px solid var(--stroke);
  margin-bottom: 1.25rem;
  flex-wrap: wrap;
}

.tab {
  appearance: none;
  border: none;
  background: transparent;
  padding: 0.65rem 1rem;
  font-size: 0.875rem;
  color: var(--muted);
  cursor: pointer;
  border-bottom: 2px solid transparent;
  margin-bottom: -1px;
}

.tab:hover {
  color: #0f172a;
}

.tab.active {
  color: var(--accent);
  border-bottom-color: var(--accent);
  font-weight: 600;
}

.panel {
  background: var(--card);
  border: 1px solid var(--stroke);
  border-radius: 6px;
  padding: 1.25rem;
}

.panel + .panel {
  margin-top: 1rem;
}

.panel h2 {
  margin: 0 0 0.75rem;
  font-size: 1.05rem;
  font-weight: 650;
}

.panel h3 {
  margin: 1rem 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
}

.muted {
  color: var(--muted);
  font-size: 0.85rem;
}

.row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  align-items: flex-end;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.field label {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--muted);
}

input[type="text"],
select {
  padding: 0.45rem 0.6rem;
  border: 1px solid var(--stroke);
  border-radius: 4px;
  font-size: 0.9rem;
  min-width: 200px;
}

.btn {
  padding: 0.5rem 1rem;
  border-radius: 4px;
  border: 1px solid var(--accent);
  background: var(--accent);
  color: #fff;
  font-size: 0.875rem;
  cursor: pointer;
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.btn.secondary {
  background: #fff;
  color: var(--accent);
}

.chip-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
  margin-top: 0.5rem;
}

.chip {
  font-size: 0.75rem;
  padding: 0.2rem 0.5rem;
  border-radius: 3px;
  background: var(--accent-soft);
  color: #1e3a8a;
  border: none;
  cursor: pointer;
}

.chip:hover {
  background: #bfdbfe;
}

.step-list {
  list-style: none;
  padding: 0;
  margin: 0.75rem 0 0;
}

.step-list li {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  padding: 0.35rem 0;
  font-size: 0.875rem;
  border-bottom: 1px solid #f1f5f9;
}

.step-badge {
  flex-shrink: 0;
  width: 1.5rem;
  height: 1.5rem;
  border-radius: 4px;
  background: #e2e8f0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.7rem;
  font-weight: 700;
}

.step-badge.done {
  background: #dcfce7;
  color: var(--ok);
}

.step-badge.run {
  background: var(--accent-soft);
  color: var(--accent);
}

.bullet-list {
  margin: 0.5rem 0 0;
  padding-left: 1.1rem;
  font-size: 0.875rem;
}

.risk-low {
  color: var(--ok);
}
